select 
from exam_score
where deleted = 0
  and exam_id = #{examId}
  and student_id = #{studentId}
limit 1

select es.exam_id, e.exam_name, es.student_id, u.real_name as student_name, es.objective_score, es.subjective_score, es.total_score, es.score_status from exam_score es inner join exam e on es.exam_id = e.id and e.deleted = 0 inner join sys_user u on es.student_id = u.id and u.deleted = 0 where es.deleted = 0 and es.score_status = 'WAIT_MARKING'
and es.exam_id = #{query.examId}
and e.creator_id = #{teacherId}
order by es.submit_time asc, es.id asc limit #{offset}, #{query.pageSize}

select count(1) from exam_score es inner join exam e on es.exam_id = e.id and e.deleted = 0 where es.deleted = 0 and es.score_status = 'WAIT_MARKING'
and es.exam_id = #{query.examId}
and e.creator_id = #{teacherId}

select es.id, es.exam_id, e.exam_name, es.student_id, u.real_name as student_name, es.objective_score, es.subjective_score, es.total_score, es.pass_flag, es.excellent_flag, es.rank_no, es.score_status, es.publish_time from exam_score es inner join exam e on es.exam_id = e.id and e.deleted = 0 inner join sys_user u on es.student_id = u.id and u.deleted = 0 where es.deleted = 0
and es.exam_id = #{query.examId}
and ( e.exam_name like concat('%', #{query.keyword}, '%') or u.real_name like concat('%', #{query.keyword}, '%') or u.username like concat('%', #{query.keyword}, '%') )
and e.creator_id = #{teacherId}
order by es.total_score desc, es.id asc limit #{offset}, #{query.pageSize}

select count(1) from exam_score es inner join exam e on es.exam_id = e.id and e.deleted = 0 inner join sys_user u on es.student_id = u.id and u.deleted = 0 where es.deleted = 0
and es.exam_id = #{query.examId}
and ( e.exam_name like concat('%', #{query.keyword}, '%') or u.real_name like concat('%', #{query.keyword}, '%') or u.username like concat('%', #{query.keyword}, '%') )
and e.creator_id = #{teacherId}

select es.id, es.exam_id, e.exam_name, es.student_id, u.real_name as student_name, es.objective_score, es.subjective_score, es.total_score, es.pass_flag, es.excellent_flag, es.rank_no, es.score_status, es.publish_time from exam_score es inner join exam e on es.exam_id = e.id and e.deleted = 0 inner join sys_user u on es.student_id = u.id and u.deleted = 0 where es.deleted = 0 and es.student_id = #{studentId} and e.result_published = 1
and es.exam_id = #{query.examId}
and ( e.exam_name like concat('%', #{query.keyword}, '%') or u.real_name like concat('%', #{query.keyword}, '%') or u.username like concat('%', #{query.keyword}, '%') )
order by es.id desc limit #{offset}, #{query.pageSize}

select count(1) from exam_score es inner join exam e on es.exam_id = e.id and e.deleted = 0 where es.deleted = 0 and es.student_id = #{studentId} and e.result_published = 1
and es.exam_id = #{query.examId}
and e.exam_name like concat('%', #{query.keyword}, '%')

mapper.update:
update exam_score
set rank_no = (
        select ranked.rank_no
        from (
            select id,
                   dense_rank() over (order by total_score desc, submit_time asc, id asc) as rank_no
            from exam_score
            where deleted = 0 and exam_id = #{examId}
        ) ranked
        where ranked.id = exam_score.id
    ),
    update_time = now()
where deleted = 0
  and exam_id = #{examId}

update exam_score
set publish_time = #{publishTime},
    update_time = #{publishTime}
where deleted = 0
  and exam_id = #{examId}
